/* Anvil webfonts: Geist Sans (UI face, OFL, Vercel) + JetBrains Mono (code,
   OFL, JetBrains). Import once next to anvil.css:
     import "@forge/ui/fonts.css";

   ============================================================================
   THE WOFF2 BINARIES ARE NOT COMMITTED. Until you fetch them, every rule here
   soft-fails and the metric-adjusted fallback stack below renders instead
   (system faces, size-adjusted to Geist metrics, so nothing reflows later).

   Fetch them once on your machine (needs network):

       node packages/ui/scripts/fetch-fonts.mjs

   That downloads the woff2 files from the official Fontsource mirrors of the
   Vercel and JetBrains releases into packages/ui/src/fonts/. Geist Sans has
   no variable build on Fontsource, so the four static weights Anvil uses are
   fetched individually.
   ============================================================================ */

@font-face {
  font-family: "Geist Sans";
  src: url("/@fs/Users/simon.smith/Library/Mobile Documents/com~apple~CloudDocs/Desktop/T&S/Rise_Rip/packages/ui/src/fonts/geist-sans-400.woff2") format("woff2");
  font-weight: 400;
  font-style: normal;
  font-display: swap;
}

