  font-family: "Geist Sans";
  src: url("/@fs/Users/simon.smith/Library/Mobile Documents/com~apple~CloudDocs/Desktop/T&S/Rise_Rip/packages/ui/src/fonts/geist-sans-500.woff2") format("woff2");
  font-weight: 500;
  font-style: normal;
