/* Base chrome text setting. Anvil owns app chrome only; never wrap
   learner course content (--forge-*/--fb-* stay author-themed). */
.anvil {
  font-family: var(--an-font-family-sans);
  font-size: var(--an-font-size-14);
  line-height: var(--an-font-line-14);
  font-weight: var(--an-font-weight-regular);
  color: var(--an-text-primary);
  background: var(--an-surface-base);
  -webkit-font-smoothing: antialiased;
}

